-- 030_personas_reales.sql
-- Inserta 121 personas reales + sus asignaciones a departamentos (personas_departamentos).
--
-- Correcciones aplicadas desde el CSV:
--   - "Digital Menta Marketing" = DME (nombre legal DIGITALMENTA MARKETING SL)
--   - NOURA CHACOR: DME → IMG, depto Administración
--   - GEMMA SAEZ: KAU → IMG, depto Administración
--   - MARIA DEL CARMEN JUNQUERA: KAU → IMG, depto Outbound
--   - JAVIER AREITIO: KAU, depto Outbound → Creativo
--   - RODRIGO MUNIELLO: DMM, depto Outbound → Consultoría Accounts
--   - BidBalance: columna puesto desplazada a campo Interino? (confirmado)
--   - Puestos corregidos según listado revisado del usuario
--   - Typos en nombres y emails limpiados
--
-- IDs de oficinas según migración 029 (reset):
--   001=Sant Valero, 002=Av America, 003=Ramon Turro,
--   004=Mendez Alvaro, 005=Cliente, 006=Teletrabajo
--
-- NOTA: Los IDs de departamentos Implants se buscan por subquery
--       porque no se conoce el ID exacto tras intentos fallidos de migración 028.

BEGIN;

-- Seguridad: limpiar cualquier persona residual
DELETE FROM personas_departamentos;
DELETE FROM personas;

-- ================================================================
-- PERSONAS (121 filas)
-- ================================================================
INSERT INTO personas (
  id, persona, dni, nombre, apellido_primero, apellido_segundo,
  empresa_grupo_id, ciudad_id, oficina_id,
  rango_id, puesto_id, division_id, rol_id,
  fecha_incorporacion, activo, email_corporativo, rango_es_interino
) VALUES
